/**
 * bundle-dashboard.js – Build-time bundling of UI source files into dashboard.ts
 *
 * Reads:
 *   ha-claw/src/web/ui/style.css
 *   ha-claw/src/web/ui/dashboard.html
 *   ha-claw/src/web/ui/client.js
 *
 * Generates:
 *   ha-claw/src/web/dashboard.ts
 *
 * The generated file exports a single function dashboardHtml(basePath: string): string
 * that returns the complete HTML with all CSS and JS inlined.
 *
 * WHY INLINING? Home Assistant Ingress maps URLs dynamically via
 * /api/hassio_ingress/<token>/. External CSS/JS links would break because
 * the browser can't resolve relative paths through Ingress. So everything
 * must be inlined into a single HTML response.
 *
 * Usage:
 *   node .agents/workflows/bundle-dashboard.js
 *
 * Run from the repo root (parent of ha-claw/).
 */

const fs = require('fs');
const path = require('path');

// Resolve paths relative to the repo root
const repoRoot = path.resolve(__dirname, '../..');
const uiDir = path.join(repoRoot, 'ha-claw', 'src', 'web', 'ui');
const outputPath = path.join(repoRoot, 'ha-claw', 'src', 'web', 'dashboard.ts');

// ── Read source files ──────────────────────────────────────
const css = fs.readFileSync(path.join(uiDir, 'style.css'), 'utf-8');
const html = fs.readFileSync(path.join(uiDir, 'dashboard.html'), 'utf-8');
const js = fs.readFileSync(path.join(uiDir, 'client.js'), 'utf-8');

console.log(`📖 Read: style.css (${css.split('\n').length} lines), dashboard.html (${html.split('\n').length} lines), client.js (${js.split('\n').length} lines)`);

// ── Assemble HTML ──────────────────────────────────────────
let assembled = html;

// Inject CSS into the placeholder
assembled = assembled.replace('/* __INLINE_CSS__ */', css);

// Replace the basePath marker in JS with a safe unique token.
// We do NOT inject ${basePath} yet – that would get escaped in the next step.
const BASEPATH_TOKEN = '___BASEPATH_TEMPLATE___';
const jsReady = js.replace("const base='__BASEPATH__';", "const base='" + BASEPATH_TOKEN + "';");
assembled = assembled.replace('/* __INLINE_JS__ */', jsReady);

// ── Escape for TypeScript template literal ─────────────────
// Inside a JS template literal (`...`), only two things need escaping:
//   1. Backticks (`) → must become \`
//   2. ${...} sequences → must become \${...}
//
// Backslashes do NOT need extra escaping because template literals
// treat them the same as regular strings.

// Escape backticks
assembled = assembled.replace(/`/g, '\\`');

// Escape ${...} expressions
assembled = assembled.replace(/\$\{/g, '\\${');

// NOW insert the real TypeScript template expression (after all escaping is done)
assembled = assembled.replace(new RegExp(BASEPATH_TOKEN, 'g'), '${basePath}');

// ── Generate TypeScript ────────────────────────────────────
const header = `/**
 * dashboard.ts – HTML template for the HA-Claw Web UI.
 *
 * ⚠️  AUTO-GENERATED FILE – DO NOT EDIT MANUALLY!
 *
 * This file is generated by: .agents/workflows/bundle-dashboard.js
 * Edit the source files instead:
 *   - src/web/ui/style.css       (CSS themes and styles)
 *   - src/web/ui/dashboard.html  (HTML structure)
 *   - src/web/ui/client.js       (Frontend JavaScript)
 *
 * Then run: node .agents/workflows/bundle-dashboard.js
 *
 * Three theme modes:
 * - "light"   – Clean light theme
 * - "dark"    – Clean dark theme
 * - "claw"    – Cyberpunk HA-Claw branded theme
 *
 * Default is auto-detected from HA Ingress or prefers-color-scheme.
 */

`;

// Build the file by string concatenation (NOT template literals)
const BT = String.fromCharCode(96); // backtick character
const output = header
  + 'export function dashboardHtml(basePath: string): string {\n'
  + '  return ' + BT + assembled + BT + ';\n'
  + '}\n';

// ── Write output ───────────────────────────────────────────
fs.writeFileSync(outputPath, output, 'utf-8');

const outputLines = output.split('\n').length;
console.log(`✅ Generated: dashboard.ts (${outputLines} lines)`);
console.log(`📁 Output: ${outputPath}`);
